import React from 'react';
import './PageHeader.css';

export const PageHeader: React.FC = () => (
  <div className="page-header">
    <div className="page-header__left">
      <h1 className="page-header__title">Category Analysis</h1>
      <div className="page-header__meta">
        <span className="page-header__tag">Health Supplements</span>
        <span className="page-header__sep">+3</span>
        <span className="page-header__total">Total Products: 120</span>
      </div>
    </div>

    <div className="page-header__right">
      <div className="sub-tab-group">
        {['MRP', 'SP', 'By Value'].map((t, i) => (
          <button
            key={t}
            className={`sub-tab ${i === 2 ? 'sub-tab--active' : ''}`}
          >
            {t}
          </button>
        ))}
      </div>
    </div>
  </div>
);
